import { SignIn } from "@clerk/nextjs";
import { useEffect, useRef } from "react";

const LOGO = "data:image/png;base64,";

// Animated particle/flow background
function FlowBackground() {
  const canvasRef = useRef(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    let W = canvas.width = window.innerWidth;
    let H = canvas.height = window.innerHeight;
    let animId;

    const resize = () => {
      W = canvas.width = window.innerWidth;
      H = canvas.height = window.innerHeight;
    };
    window.addEventListener("resize", resize);

    // Particles — PS5 style floating dots
    const N = 80;
    const particles = Array.from({ length: N }, () => ({
      x: Math.random() * W,
      y: Math.random() * H,
      r: Math.random() * 2.5 + 0.5,
      vx: (Math.random() - 0.5) * 0.4,
      vy: (Math.random() - 0.5) * 0.4,
      opacity: Math.random() * 0.6 + 0.1,
      hue: Math.random() < 0.5 ? 200 : 240, // cyan vs blue
    }));

    // Flow lines — liquid glass effect
    const lines = Array.from({ length: 12 }, (_, i) => ({
      y: (H / 12) * i,
      offset: Math.random() * Math.PI * 2,
      speed: 0.0005 + Math.random() * 0.001,
      amp: 60 + Math.random() * 80,
      freq: 0.003 + Math.random() * 0.002,
      opacity: 0.03 + Math.random() * 0.05,
    }));

    // Orbs — liquid glass blobs
    const orbs = [
      { x: W * 0.15, y: H * 0.3, r: 280, color: "56,189,248", speed: 0.0003 },
      { x: W * 0.85, y: H * 0.7, r: 240, color: "99,102,241", speed: 0.0004 },
      { x: W * 0.5, y: H * 0.15, r: 180, color: "14,165,233", speed: 0.0005 },
    ];

    let t = 0;
    const draw = () => {
      ctx.clearRect(0, 0, W, H);
      t += 1;

      // Dark bg gradient
      const bg = ctx.createLinearGradient(0, 0, W, H);
      bg.addColorStop(0, "#020510");
      bg.addColorStop(0.5, "#04060e");
      bg.addColorStop(1, "#020814");
      ctx.fillStyle = bg;
      ctx.fillRect(0, 0, W, H);

      // Orbs (liquid glass blobs)
      orbs.forEach(orb => {
        orb.x += Math.sin(t * orb.speed) * 0.8;
        orb.y += Math.cos(t * orb.speed * 0.7) * 0.6;
        const g = ctx.createRadialGradient(orb.x, orb.y, 0, orb.x, orb.y, orb.r);
        g.addColorStop(0, `rgba(${orb.color},0.12)`);
        g.addColorStop(0.5, `rgba(${orb.color},0.05)`);
        g.addColorStop(1, `rgba(${orb.color},0)`);
        ctx.fillStyle = g;
        ctx.beginPath();
        ctx.arc(orb.x, orb.y, orb.r, 0, Math.PI * 2);
        ctx.fill();
      });

      // Flow lines
      lines.forEach(line => {
        line.offset += line.speed;
        ctx.beginPath();
        ctx.moveTo(0, line.y);
        for (let x = 0; x <= W; x += 4) {
          const y = line.y + Math.sin(x * line.freq + line.offset) * line.amp
                          + Math.sin(x * line.freq * 0.5 + line.offset * 1.3) * line.amp * 0.4;
          ctx.lineTo(x, y);
        }
        const grad = ctx.createLinearGradient(0, 0, W, 0);
        grad.addColorStop(0, `rgba(56,189,248,0)`);
        grad.addColorStop(0.3, `rgba(56,189,248,${line.opacity})`);
        grad.addColorStop(0.7, `rgba(99,102,241,${line.opacity})`);
        grad.addColorStop(1, `rgba(99,102,241,0)`);
        ctx.strokeStyle = grad;
        ctx.lineWidth = 1;
        ctx.stroke();
      });

      // Particles
      particles.forEach(p => {
        p.x += p.vx;
        p.y += p.vy;
        if (p.x < 0) p.x = W;
        if (p.x > W) p.x = 0;
        if (p.y < 0) p.y = H;
        if (p.y > H) p.y = 0;
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
        ctx.fillStyle = `hsla(${p.hue},90%,70%,${p.opacity})`;
        ctx.fill();
      });

      // Connect nearby particles
      for (let i = 0; i < particles.length; i++) {
        for (let j = i + 1; j < particles.length; j++) {
          const dx = particles[i].x - particles[j].x;
          const dy = particles[i].y - particles[j].y;
          const dist = Math.sqrt(dx * dx + dy * dy);
          if (dist < 100) {
            ctx.beginPath();
            ctx.moveTo(particles[i].x, particles[i].y);
            ctx.lineTo(particles[j].x, particles[j].y);
            ctx.strokeStyle = `rgba(56,189,248,${0.08 * (1 - dist / 100)})`;
            ctx.lineWidth = 0.5;
            ctx.stroke();
          }
        }
      }

      animId = requestAnimationFrame(draw);
    };
    draw();
    return () => { cancelAnimationFrame(animId); window.removeEventListener("resize", resize); };
  }, []);

  return (
    <canvas ref={canvasRef} style={{
      position:"fixed", inset:0, zIndex:0, pointerEvents:"none"
    }}/>
  );
}

